// ============================================================
// WF-05 [1] Resolve Current Period (YYYY.MM)
// Приоритет: docDate из входа → текущая дата
// ============================================================

const itemJson = $json;
let year, month;

const docDate = itemJson.docDate || '';
const parts = docDate.split('.');
if (parts.length === 3 && parts[2] && parts[1]) {
  month = parts[1].padStart(2, '0');
  year = parts[2];
} else {
  const now = new Date();
  month = String(now.getMonth() + 1).padStart(2, '0');
  year = String(now.getFullYear());
}

const periodLabel = `${year}.${month}`;

// Нормализация страны (дефолт Беларусь)
const rawCountry = String(itemJson.country || '').trim();
const country = rawCountry === 'Польша' ? 'Польша' : 'Беларусь';

return {
  json: {
    ...itemJson,
    periodLabel,
    periodYear: year,
    periodMonth: month,
    country
  }
};

// ============================================================
// WF-05 [2b] Convert RUB → BYN (курс НБРБ на дату документа)
// Сценарий: счёт выставлен нашим бел. юр. лицом (Квае Лаб) российскому
// контрагенту в российских рублях. В реестр сумма пишется в BYN по
// официальному курсу Нацбанка РБ на дату выставления счёта (docDate).
// Источник курса: https://api.nbrb.by/exrates/rates/RUB?parammode=2&ondate=YYYY-MM-DD
// ============================================================

function toIso(d) {
  const m = String(d || '').match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
  return m ? `${m[3]}-${m[2]}-${m[1]}` : '';
}
function toReadable(iso) {
  const m = String(iso || '').match(/^(\d{4})-(\d{2})-(\d{2})$/);
  return m ? `${m[3]}.${m[2]}.${m[1]}` : iso;
}

const out = [];
for (const it of $input.all()) {
  const j = { ...it.json };

  const currency = String(j.currency || '').toUpperCase();
  const cp = String(j.counterpartyCountry || '').trim().toLowerCase();
  const isRuCp = cp.includes('росс') || cp === 'ru' || cp.includes('russia');

  // сумма как абсолютное число
  let amt = 0;
  if (typeof j.amount === 'number') amt = j.amount;
  else if (typeof j.amount === 'string') {
    amt = parseFloat(j.amount.replace(/[^0-9.,\-]/g, '').replace(',', '.')) || 0;
  }
  amt = Math.abs(amt);

  // --- Проверка: росс. контрагент, но валюта не RUB ---
  if (isRuCp && currency && currency !== 'RUB') {
    j.aiDescription = (j.aiDescription ? j.aiDescription + ' ' : '') +
      `[⚠️ РФ-контрагент, но валюта ${currency}, а не RUB — проверьте документ]`;
  }

  // --- Конвертация RUB → BYN по курсу НБРБ на дату документа ---
  if (currency === 'RUB' && amt > 0) {
    let ondate = toIso(j.docDate);
    if (!ondate) {
      const now = new Date();
      ondate = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
    }
    try {
      const res = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://api.nbrb.by/exrates/rates/RUB?parammode=2&ondate=${ondate}`,
        json: true,
        timeout: 10000
      });
      const rate = Number(res && res.Cur_OfficialRate);
      const scale = Number(res && res.Cur_Scale) || 1;
      if (!rate || rate <= 0) throw new Error('НБРБ вернул пустой курс');

      const byn = Math.round((amt * rate / scale) * 100) / 100;

      j._origAmount = amt;
      j._origCurrency = 'RUB';
      j._nbrbRate = rate;
      j._nbrbScale = scale;
      j._nbrbDate = ondate;
      j._converted = true;

      j.amount = byn;
      j.currency = 'BYN';

      j.aiDescription = (j.aiDescription ? j.aiDescription + ' ' : '') +
        `🔁 Конвертация ${amt.toFixed(2)} RUB → ${byn.toFixed(2)} BYN по курсу НБРБ ${rate} BYN / ${scale} RUB на ${toReadable(ondate)}.`;
    } catch (e) {
      j._converted = false;
      j._convertError = String((e && e.message) || e);
      j.aiDescription = (j.aiDescription ? j.aiDescription + ' ' : '') +
        `[⚠️ Не удалось получить курс НБРБ на ${toReadable(ondate)} — сумма оставлена в RUB, нужна ручная конвертация]`;
    }
  }

  out.push({ json: j });
}

return out;

// ============================================================
// WF-05 [3] ID Generator + Row Builder (v2.4)
// Изменения v2.4: добавлен invoice_number → колонка M реестра
// ============================================================

const input = $('Convert RUB to BYN (NBRB)').item.json;

// counterRow: либо из Get Counter Row (true-ветка), либо только что создана (false-ветка)
let counterRow;
try {
  counterRow = $('Counter Row Exists?').item.json;
} catch (e) {
  counterRow = null;
}
if (!counterRow || !counterRow['Период']) {
  counterRow = {
    'Период': input.periodLabel,
    'Страна': input.country || 'Беларусь',
    'Поступления (0.XXXX)': 0,
    'Выбытия (1.XXXX)': 0
  };
}

// --- Тип операции (0 = Поступление, 1 = Выбытие) ---
const typeCode = input.status === 'Поступление' ? 0 : 1;
const counterKey = typeCode === 0 ? 'Поступления (0.XXXX)' : 'Выбытия (1.XXXX)';

// --- Инкремент счётчика ---
const currentCount = parseInt(counterRow[counterKey] || '0', 10) || 0;
const newCount = currentCount + 1;
const nrId = `${typeCode}.${String(newCount).padStart(4, '0')}`;

// --- UUID v4 ---
const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c === 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

// --- Обновлённые значения счётчиков ---
const newIncome  = typeCode === 0 ? newCount : parseInt(counterRow['Поступления (0.XXXX)'] || '0', 10);
const newOutcome = typeCode === 1 ? newCount : parseInt(counterRow['Выбытия (1.XXXX)']     || '0', 10);

// --- Обработка суммы (v2.3) ---
const rawAmt = input.amount;
let absAmount = 0;
if (typeof rawAmt === 'number') {
  absAmount = Math.abs(rawAmt);
} else if (typeof rawAmt === 'string' && rawAmt.trim()) {
  const parsed = parseFloat(rawAmt.replace(/[^0-9.,\-]/g, '').replace(',', '.'));
  absAmount = Math.abs(isNaN(parsed) ? 0 : parsed);
}

const signedAmount = typeCode === 0 ? absAmount : -absAmount;
const currency = String(input.currency || '').toUpperCase();

// === Оригинальная сумма в RUB (если была конвертация RUB→BYN) ===
const origRub = (input._converted && input._origCurrency === 'RUB' && (Number(input._origAmount) || 0) > 0)
  ? (typeCode === 0 ? Math.abs(Number(input._origAmount)) : -Math.abs(Number(input._origAmount)))
  : '';

// === v2.4: invoice_number ===
const invoiceNumber = String(input.invoice_number || '').trim();

// --- Сборка строки реестра (A–M видимые + L скрытый UUID) ---
const row = {
  'Nr ID':              nrId,
  'Статус':             input.status || '',
  'Дата документа':     input.docDate || '',
  'Контрагент':         input.counterparty || '',
  'Дата оплаты':        input.payDate || '',
  'Сумма':              signedAmount,
  'Валюта':             currency,
  'Сумма в RUB (оригинал)': origRub,
  'Статус оплаты':      input.payStatus || '',
  'Страна':             input.country || 'Беларусь',
  'Ссылка на документ': input.driveUrl || '',
  'Описание AI':        input.aiDescription || '',
  'UUID':               uuid,
  'Номер инвойса':      invoiceNumber
};

return {
  json: {
    ...input,
    nrId,
    uuid,
    invoiceNumber,
    typeCode,
    counterKey,
    newCount,
    newIncome,
    newOutcome,
    signedAmount,
    currency,
    registryRow: row
  }
};

// ============================================================
// WF-05 [6] Confirmation Builder (v2.4)
// Изменения v2.4: строка 🧾 invoice_number (только если не пустой)
// ============================================================

const d = $('Generate Nr ID & Build Row').item.json;

// --- Страна ---
const country = d.country || 'Беларусь';
const isPoland = (country === 'Польша');

// Флаг страны
const flag = isPoland
  ? '\uD83C\uDDF5\uD83C\uDDF1'  // 🇵🇱
  : '\uD83C\uDDE7\uD83C\uDDFE'; // 🇧🇾

// --- Путь Drive ---
const rootFolder = isPoland ? 'Poland' : 'Belarus';
const yearMonth  = d.periodLabel || '';
const subFolder  = d.status === 'Поступление' ? 'income' : 'outcome';

const driveLink = d.driveUrl
  ? `\n\uD83D\uDD17 [Ссылка на файл](${d.driveUrl})`
  : '';

const folderHint = d.driveUrl
  ? `\n\uD83D\uDCC1 ${rootFolder}/${yearMonth}/${subFolder}/`
  : '';

// --- Сумма ---
const signedAmount = parseFloat(d.signedAmount);
const currency     = String(d.currency || '').toUpperCase();
let amountDisplay  = '\u2014';
if (!isNaN(signedAmount) && signedAmount !== 0) {
  const sign = signedAmount >= 0 ? '+' : '-';
  const abs  = Math.abs(signedAmount);
  const formatted = Number.isInteger(abs) ? String(abs) : abs.toFixed(2);
  amountDisplay = `${sign}${formatted}${currency ? ' ' + currency : ''}`;
}

// === v2.4: строка инвойса (только если поле не пустое) ===
const invoiceNumber = String(d.invoiceNumber || '').trim();
const invoiceLine   = invoiceNumber ? `\n\uD83E\uDDFE ${invoiceNumber}` : '';

// --- Шаблон подтверждения ---
const confirmationText =
`\u2705 Записано

\uD83D\uDCCC ${d.nrId} | ${d.status || '\u2014'}
${flag} ${country}
\uD83D\uDCC5 ${d.docDate || '\u2014'}
\uD83C\uDFE2 ${d.counterparty || '\u2014'}${invoiceLine}
\uD83D\uDCB0 ${amountDisplay} | ${d.payStatus || '\u2014'}${folderHint}${driveLink}

\uD83D\uDCAC ${d.aiDescription || ''}`;

return {
  json: {
    nrId:             d.nrId,
    uuid:             d.uuid,
    chatId:           d.chatId || '',
    confirmationText,
    periodLabel:      d.periodLabel,
    status:           d.status,
    signedAmount,
    currency,
    country
  }
};
